                            )
                        ]
                    )
                ]
                if lab.get("interpretation")
                else None,
            )
            resources.append(obs.model_dump(exclude_none=True, mode="json"))

        # Observations - vitals
        for vit in entry.get("vitals", []):
            obs = Observation(
